#include "mlpa/reporting/Reporter.h"
#include <sstream>
namespace mlpa { namespace { std::string esc(std::string s){std::string o; for(char c:s){ if(c=='"')o+="\\\""; else if(c=='\\')o+="\\\\"; else if(c=='\n')o+="\\n"; else o+=c;} return o;} }
std::string JsonReporter::render(const AnalysisResult &r) const { std::ostringstream os; os<<"{\n  \"metrics\": {\n"<<"    \"classes\": "<<r.metrics.classCount<<",\n    \"functions\": "<<r.metrics.functionCount<<",\n    \"averageFunctionLength\": "<<r.metrics.averageFunctionLength<<",\n    \"cyclomaticComplexity\": "<<r.metrics.totalCyclomaticComplexity<<",\n    \"maxNestingDepth\": "<<r.metrics.maxNestingDepth<<",\n    \"qualityScore\": "<<r.metrics.qualityScore<<"\n  },\n  \"issues\": [\n"; for(size_t i=0;i<r.issues.size();++i){auto &x=r.issues[i]; os<<"    {\"ruleId\": \""<<esc(x.ruleId)<<"\", \"category\": \""<<toString(x.category)<<"\", \"severity\": \""<<toString(x.severity)<<"\", \"file\": \""<<esc(x.location.file)<<"\", \"line\": "<<x.location.line<<", \"title\": \""<<esc(x.title)<<"\", \"explanation\": \""<<esc(x.explanation)<<"\", \"suggestion\": \""<<esc(x.suggestion)<<"\"}"<<(i+1<r.issues.size()?",":"")<<"\n";} os<<"  ]\n}\n"; return os.str(); }
}
